#!/usr/bin/env python3
"""Add missing /// docs to public Rust items. Prints updated source to stdout."""
import re
import sys
from pathlib import Path

MAX_LINE = 80

def wrap_doc(text: str, kind: str) -> list[str]:
    text = text.strip()
    if len(text) <= MAX_LINE:
        return [f"/// {text}"]
    words = text.split()
    lines, cur = [], ""
    for w in words:
        trial = (cur + " " + w).strip()
        if len(trial) <= MAX_LINE - 4:
            cur = trial
        else:
            if cur:
                lines.append(f"/// {cur}")
            cur = w
    if cur:
        lines.append(f"/// {cur}")
    return lines[:3]

def humanize(name: str) -> str:
    s = re.sub(r"([a-z0-9])([A-Z])", r"\1 \2", name)
    s = s.replace("_", " ")
    return s.lower()

def doc_for_item(line: str, ctx: str) -> list[str]:
    m = re.match(r"\s*pub(?:\([^)]*\))?\s+(async\s+)?(unsafe\s+)?(const\s+)?(struct|enum|trait|fn|type|mod|static|const)\s+(\w+)", line)
    if m:
        kind, name = m.group(4), m.group(5)
        if kind == "mod":
            return wrap_doc(f"{humanize(name)} module.", "mod")
        if kind == "fn":
            return wrap_doc(f"{humanize(name)}.", "fn")
        if kind == "struct":
            return wrap_doc(f"{humanize(name)}.", "struct")
        if kind == "enum":
            return wrap_doc(f"{humanize(name)}.", "enum")
        if kind == "trait":
            return wrap_doc(f"{humanize(name)} trait.", "trait")
        if kind in ("const", "static"):
            return wrap_doc(f"{humanize(name)} constant.", kind)
        if kind == "type":
            return wrap_doc(f"{humanize(name)} type alias.", "type")
    m = re.match(r"\s*pub\s+(\w+)(?:\s*:\s*[^,{]+)?[,}]", line)
    if m and ctx in ("struct", "enum"):
        return wrap_doc(f"{humanize(m.group(1))} field.", "field")
    m = re.match(r"\s*(\w+)\s*\{", line)
    if m and ctx == "enum" and not line.strip().startswith("pub"):
        return wrap_doc(f"{humanize(m.group(1))} variant.", "variant")
    return wrap_doc("Public item.", "item")

def has_doc(lines, i):
    j = i - 1
    while j >= 0 and lines[j].strip() == "":
        j -= 1
    if j < 0:
        return False
    s = lines[j].strip()
    if s.startswith("///") or s.startswith("#![") or s.startswith("//!"):
        return True
    if s.startswith("#["):
        jj = j - 1
        while jj >= 0 and lines[jj].strip() == "":
            jj -= 1
        if jj >= 0 and lines[jj].strip().startswith("///"):
            return True
    return False

def process(path: Path) -> str:
    text = path.read_text()
    lines = text.splitlines()
    out = []
    ctx_stack = []
    i = 0
    if not any(l.strip().startswith("#!") for l in lines[:5]):
        stem = path.stem.replace("_", " ")
        if path.name == "mod.rs":
            parent = path.parent.name.replace("_", " ")
            crate_doc = wrap_doc(f"{parent} plugin module.", "crate")
        else:
            crate_doc = wrap_doc(f"{stem} module.", "crate")
        out.extend(crate_doc)
        out.append("")

    while i < len(lines):
        line = lines[i]
        stripped = line.strip()

        # track enum/struct context for fields/variants
        if re.match(r"\s*pub\s+struct\s+", line):
            ctx_stack.append("struct")
        elif re.match(r"\s*pub\s+enum\s+", line):
            ctx_stack.append("enum")
        elif stripped == "}" and ctx_stack:
            ctx_stack.pop()

        needs_doc = False
        if re.match(r"\s*pub(?:\([^)]*\))?\s+", line) and not stripped.startswith("pub use"):
            needs_doc = True
        elif ctx_stack and ctx_stack[-1] == "enum":
            m = re.match(r"\s*(\w+)\s*(\{|,|\()", line)
            if m and not stripped.startswith("//") and not stripped.startswith("pub"):
                needs_doc = True

        if needs_doc and not has_doc(lines, i):
            ctx = ctx_stack[-1] if ctx_stack else ""
            out.extend(doc_for_item(line, ctx))
        out.append(line)
        i += 1

    return "\n".join(out) + ("\n" if text.endswith("\n") else "")

if __name__ == "__main__":
    for p in sys.argv[1:]:
        print(process(Path(p)), end="")
