#!/usr/bin/env python3
"""Insert /// docs at rustc missing_docs locations for a crate."""
import re, subprocess, sys
from pathlib import Path

CRATE = Path("/workspace/crack_demo/demo_resolution_selector_web_bevy")
PREFIX = "crack_demo/demo_resolution_selector_web_bevy/"

def humanize(name: str) -> str:
    s = re.sub(r"([a-z0-9])([A-Z])", r"\1 \2", name)
    return s.replace("_", " ").strip().lower()

def wrap(text: str):
    text = re.sub(r"\s+", " ", text.strip())
    if len(text) <= 76:
        return [f"/// {text}"]
    words, lines, cur = text.split(), [], ""
    for w in words:
        t = (cur + " " + w).strip()
        if len(t) <= 76:
            cur = t
        else:
            lines.append(f"/// {cur}")
            cur = w
            if len(lines) == 3:
                break
    if cur and len(lines) < 3:
        lines.append(f"/// {cur}")
    return lines[:3]

def guess_doc(path: Path, line_no: int, msg: str, line: str) -> list[str]:
    if "crate" in msg:
        name = path.parent.name if path.name == "mod.rs" else path.stem
        return wrap(f"{humanize(name)} module for the demo game.")
    m = re.search(r"pub(?:\([^)]*\))?\s+(?:async\s+)?(?:unsafe\s+)?(?:const\s+)?(struct|enum|trait|fn|mod|type|static|const)\s+(\w+)", line)
    if m:
        kind, name = m.group(1), m.group(2)
        return wrap({
            "mod": f"{humanize(name)} submodule.",
            "fn": f"{humanize(name)}.",
            "struct": f"{humanize(name)}.",
            "enum": f"{humanize(name)}.",
            "trait": f"{humanize(name)} trait.",
            "const": f"{humanize(name)} constant.",
            "static": f"{humanize(name)} static.",
            "type": f"{humanize(name)} type alias.",
        }[kind])
    m = re.search(r"pub\s+(\w+)\s*:", line)
    if m:
        return wrap(f"{humanize(m.group(1))} field.")
    m = re.match(r"\s*(\w+)\s*[\{,]", line)
    if m and "variant" in msg:
        return wrap(f"{humanize(m.group(1))} variant.")
    m = re.search(r"fn\s+(\w+)", line)
    if m:
        return wrap(f"{humanize(m.group(1))}.")
    return wrap("Documented public item.")

def has_doc(lines, idx):
    j = idx - 1
    while j >= 0 and lines[j].strip() == "":
        j -= 1
    if j < 0:
        return False
    s = lines[j].strip()
    if s.startswith("///") or s.startswith("//!"):
        return True
    if s.startswith("#["):
        k = j - 1
        while k >= 0 and lines[k].strip() == "":
            k -= 1
        return k >= 0 and lines[k].strip().startswith("///")
    return False

def parse_warnings(log: str):
    warnings = []
    lines = log.splitlines()
    i = 0
    while i < len(lines):
        if "missing documentation" in lines[i]:
            msg = lines[i]
            if i + 1 < len(lines) and lines[i+1].strip().startswith("-->"):
                loc = lines[i+1].strip()[4:].strip()
                m = re.match(r"(.+):(\d+):(\d+)", loc)
                if m and PREFIX in m.group(1):
                    warnings.append((m.group(1).split(PREFIX,1)[1], int(m.group(2)), msg, int(m.group(3))))
        i += 1
    return warnings

def build_log():
    r = subprocess.run(
        ["cargo", "build"],
        cwd=CRATE,
        capture_output=True,
        text=True,
    )
    return r.stdout + r.stderr

def apply_batch(warnings, max_items=200):
    by_file = {}
    for rel, line_no, msg, col in warnings[:max_items]:
        by_file.setdefault(rel, []).append((line_no, msg, col))
    changed = 0
    for rel, items in by_file.items():
        path = CRATE / rel
        lines = path.read_text().splitlines()
        for line_no, msg, col in sorted(items, key=lambda x: -x[0]):
            idx = line_no - 1
            if idx < 0 or idx >= len(lines):
                continue
            if has_doc(lines, idx):
                continue
            doc = guess_doc(path, line_no, msg, lines[idx])
            # for derive attrs, insert before attributes
            insert_at = idx
            if insert_at > 0 and lines[insert_at-1].strip().startswith("#["):
                while insert_at > 0 and (lines[insert_at-1].strip().startswith("#[") or lines[insert_at-1].strip() == ""):
