118:d93|fn simple_camera_movement(
119:cd8|    keyboard: Res<ButtonInput<KeyCode>>,
120:9c2|    mouse_button: Res<ButtonInput<MouseButton>>,
121:607|    mut mouse_motion: MessageReader<MouseMotion>,
122:969|    mut camera_query: Query<&mut Transform, With<Camera>>,
123:636|    time: Res<Time>,
124:510|) {
125:6d7|    let Some(mut transform) = camera_query.iter_mut().next() else {
126:d32|        return;
127:aa9|    };
128:d05|
129:347|    // Rotate
130:4b3|    if mouse_button.pressed(MouseButton::Left) {
131:bb5|        let (mut yaw, mut pitch, _) = transform.rotation.to_euler(EulerRot::YXZ);
132:1a4|        let sensitivity = 0.003;
133:1c0|        for event in mouse_motion.read() {
134:d86|            yaw -= event.delta.x * sensitivity;
135:510|            pitch -= event.delta.y * sensitivity;
136:b18|        }
137:01b|        pitch = pitch.clamp(-89.9f32.to_radians(), 89.9f32.to_radians());
138:80b|        transform.rotation = Quat::from_euler(EulerRot::YXZ, yaw, pitch, 0.0);
139:a32|    } else {
140:a78|        for _ in mouse_motion.read() {}
141:b18|    }
142:d05|
143:221|    // Translate
144:d43|    let speed = 20.0;
145:2f4|    let mut forward = *transform.forward();
146:349|    forward.y = 0.0;
147:33b|    let forward = forward.normalize_or_zero();
148:f01|    let mut right = *transform.right();
149:802|    right.y = 0.0;
150:616|    let right = right.normalize_or_zero();
151:d05|
152:4ae|    if keyboard.pressed(KeyCode::KeyW) {
153:304|        transform.translation += forward * speed * time.delta_secs();
154:b18|    }
155:fbf|    if keyboard.pressed(KeyCode::KeyS) {
156:a83|        transform.translation -= forward * speed * time.delta_secs();
157:b18|    }
158:423|    if keyboard.pressed(KeyCode::KeyA) {
159:34b|        transform.translation -= right * speed * time.delta_secs();
160:b18|    }
161:ef6|    if keyboard.pressed(KeyCode::KeyD) {
162:766|        transform.translation += right * speed * time.delta_secs();
163:b18|    }
164:4ac|    if keyboard.pressed(KeyCode::Space) {
165:8ef|        transform.translation.y += speed * time.delta_secs();
166:b18|    }
167:724|    if keyboard.pressed(KeyCode::ControlLeft) {
168:afd|        transform.translation.y -= speed * time.delta_secs();
169:b18|    }
170:b18|}

