77:900|/// A bumpy heightmap laid over the flat debug ground: heights in [-0.25, 0.25] so the
78:0bb|/// bumps and the original ground cubes (tops at y = 0) intertwine — peaks stick out,
79:ced|/// valleys sink below the flat floor. Rendered and collidable (trimesh from the same
80:ae3|/// vertices, so visuals == physics).
81:3bb|fn spawn_bumpy_heightmap(
82:4f2|    mut commands: Commands,
83:bf8|    mut meshes: ResMut<Assets<Mesh>>,
84:5ef|    mut materials: ResMut<Assets<StandardMaterial>>,
85:510|) {
86:166|    const AMPLITUDE: f32 = 0.4;
87:4d6|    let n = 151usize; // vertices per side
88:c43|    let size = 300.0f32; // meters, centered at origin
89:285|    let step = size / (n - 1) as f32;
90:fe4|    let half = size / 2.0;
91:d05|
92:a88|    // ~7m wavelength, amplitude 0.4m
93:415|    let hfun = |x: f32, z: f32| -> f32 { AMPLITUDE * (x * 0.9).sin() * (z * 0.9).sin() };
94:d05|
95:7c6|    let mut positions = Vec::with_capacity(n * n);
96:6b3|    let mut uvs = Vec::with_capacity(n * n);
97:adb|    for i in 0..n {
98:332|        for j in 0..n {
99:4f9|            let x = -half + i as f32 * step;
100:de5|            let z = -half + j as f32 * step;
101:639|            positions.push([x, hfun(x, z), z]);
102:425|            uvs.push([i as f32 * 0.5, j as f32 * 0.5]);
103:b18|        }
104:b18|    }
105:a00|    let mut indices: Vec<u32> = Vec::with_capacity((n - 1) * (n - 1) * 6);
106:dc7|    for i in 0..n - 1 {
107:79d|        for j in 0..n - 1 {
108:597|            let a = (i * n + j) as u32;
109:726|            let b = (i * n + j + 1) as u32;
110:a65|            let c = ((i + 1) * n + j) as u32;
111:430|            let d = ((i + 1) * n + j + 1) as u32;
112:362|            indices.extend_from_slice(&[a, b, c, b, d, c]);
113:b18|        }
114:b18|    }
115:d05|
116:ae2|    let mut mesh = Mesh::new(
