127:d05|
128:ec4|    commands.spawn((
129:fde|        Name::new("BumpyHeightmap"),
130:cee|        Mesh3d(meshes.add(mesh)),
131:43a|        MeshMaterial3d(materials.add(StandardMaterial {
132:17e|            base_color: Color::srgb(0.45, 0.52, 0.4),
