175:848|            continue;
176:b18|        }
177:127|        let mut parts = line.split(',');
178:b53|        let name = parts.next().unwrap_or("").trim().to_string();
179:5d9|        if name.is_empty() {
180:848|            continue;
181:b18|        }
182:86d|        // `attenuation` is the audible reference distance in metres. The manifest usually
183:fda|        // omits it, so default to a gameplay-sized range instead of 1.0 (which made sounds
184:b28|        // die within a couple of metres, see `play_sound_observer`).
185:9e7|        let attenuation = parts
