187:0e5|            .and_then(|s| s.trim().parse::<f32>().ok())
188:973|            .unwrap_or(45.0);
189:eca|        let volume = parts
190:c92|            .next()
191:0e5|            .and_then(|s| s.trim().parse::<f32>().ok())
192:199|            .unwrap_or(1.0);
193:d05|
194:2e8|        let url = format!("{}{}", bootstrap.folder, name);
195:10b|        let handle = asset_server.load::<AudioSource>(url.clone());
196:4a6|        sounds.push(SoundEntry {
197:1a1|            name,
198:f93|            url,
199:d92|            handle,
200:385|            attenuation,
201:860|            volume,
202:d86|        });
203:b18|    }
